fn search(query: &str, contents: &str, case_sensitive: bool) -> Vec<(usize, String)> {
    let query_cmp = if case_sensitive {
        query.to_string()
    } else {
        query.to_lowercase()
    };

    contents
        .lines()
        .enumerate()
        .filter_map(|(i, line)| {
            let line_cmp = if case_sensitive {
                line.to_string()
            } else {
                line.to_lowercase()
            };
            if line_cmp.contains(&query_cmp) {
                Some((i + 1, line.to_string()))
            } else {
                None
            }
        })
        .collect()
}

fn main() {
    let query = "rust";
    let contents = "Rust is a systems language.\nI love programming in rust.\nMemory safety is key.\nRust has zero-cost abstractions.";

    let results = search(query, contents, false);
    println!("Found {} matches:", results.len());
    for (line_num, line) in &results {
        println!("  {}: {}", line_num, line);
    }
}
